from collections import deque, defaultdict

class Solution(object):
    def minMoves(self, matrix):
        m, n = len(matrix), len(matrix[0])
        if matrix[0][0] == '#':
            return -1

        # Group portal positions by letter
        portals = defaultdict(list)
        for i in range(m):
            for j in range(n):
                c = matrix[i][j]
                if c.isupper():
                    portals[c].append((i, j))

        dist = [[float('inf')] * n for _ in range(m)]
        dist[0][0] = 0
        used_portals = set()
        queue = deque([(0, 0, 0)])  # (dist, row, col)

        while queue:
            d, r, c = queue.popleft()
            if d > dist[r][c]:
                continue
            if r == m-1 and c == n-1:
                return d
            # Teleport if current cell is a portal and unused
            cell = matrix[r][c]
            if cell.isupper() and cell not in used_portals:
                used_portals.add(cell)
                for nr, nc in portals[cell]:
                    if (nr, nc) != (r, c) and dist[nr][nc] > d:
                        dist[nr][nc] = d
                        queue.appendleft((d, nr, nc))  # 0-cost move
            # Normal moves
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < m and 0 <= nc < n and matrix[nr][nc] != '#':
                    nd = d + 1
                    if nd < dist[nr][nc]:
                        dist[nr][nc] = nd
                        queue.append((nd, nr, nc))

        return dist[m-1][n-1] if dist[m-1][n-1] != float('inf') else -1
